          borderRadius: 8,
          background: "#2563eb",
          color: "white",
          textAlign: "center",
          fontWeight: 600,
          cursor: "pointer",
        }}
        onClick={applyPriceFilter}
      >
        Aplicar filtro
      </div>
    </div>
  );
}

